(window.webpackJsonp=window.webpackJsonp||[]).push([[380],{1007:function(n,e){n.exports="\x3c!-- \ntitle: 01-入门\nsort: \n--\x3e \n\n## HelloWorld\n\n> `index.js`\n>\n> `index.html`\n\n```js\nlet electron = require('electron')\n\nelectron.app.on('ready', ()=>{\n    let mainWindow = new electron.BrowserWindow({width: 960,height: 720})\n    mainWindow.loadFile('index.html')\n})\n\nelectron .\n```\n\n## First\n\n![electron](https://gitee.com/nmdfzf404/Image-hosting/raw/master/2020/20201214222757.png)\n\n> `main.js`\n\n```js\nconst { app, BrowserWindow } = require('electron');\n\n// 窗体创建函数\nconst createWindow = () => {\n  const mainWindow = new BrowserWindow({\n    width: 800,\n    height: 600,\n    // 允许子页面调用api\n    webPreferences: {\n      nodeIntegration: true\n    }\n  });\n\n  // 加载文件\n  mainWindow.loadFile('src/index.html');\n\n  // 开启调试工具\n  mainWindow.webContents.openDevTools();\n};\n\n// 初始化完成后创建窗口\napp.whenReady().then(createWindow);\n\n// 关闭所有窗口后推出\napp.on('window-all-closed', () => {\n  // OS X除外\n  if (process.platform !== 'darwin') {\n    app.quit();\n  }\n});\n```\n\n> `index.html`\n\n```html\n<html lang=\"en\">\n\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Hello Electron</title>\n</head>\n\n<body>\n  <h1>💖 Hello Electron</h1>\n  <button id=\"btn\">Get Info</button>\n  <div class=\"info\"></div>\n  <script>\n    const fs = require('fs');\n\n\t\twindow.onload = () => {\n      let btn = this.document.getElementById('btn');\n      let info = this.document.getElementsByClassName('info');\n      btn.onclick = () => {\n        fs.readFile('info.txt', (err, data) => {\n          info[0].innerHTML = `<p>${data}</p>`\n        })\n    \t}\n\t\t}\n  <\/script>\n</body>\n</html>\n```\n\n## 打包\n\n```bash\nyarn create electron-app .\nyarn start\nyarn make\n```\n"}}]);